# compute_t2fd.py — compute per-team funnel metrics from the event store

import httpx
from datetime import datetime, timezone
from collections import defaultdict

def get_events(start: str, end: str) -> list[dict]:
    resp = httpx.get(
        "https://events.internal/api/platform-milestones",
        params={"start": start, "end": end, "limit": 10_000},
    )
    return resp.json()["events"]

def compute_funnel(events: list[dict]) -> dict:
    # Group events by team, find first occurrence of each milestone
    team_milestones: dict[str, dict[str, datetime]] = defaultdict(dict)
    for ev in events:
        tid = ev["team_id"]
        ms  = ev["milestone"]
        ts  = datetime.fromisoformat(ev["occurred_at"])
        if ms not in team_milestones[tid]:
            team_milestones[tid][ms] = ts

    # Compute deltas for teams that reached each milestone
    t_prov, t_call, t_eval, t_deploy = [], [], [], []
    for tid, ms in team_milestones.items():
        if "M1" not in ms:
            continue
        m1 = ms["M1"]
        if "M2" in ms: t_prov.append( (ms["M2"] - m1).total_seconds() / 3600)
        if "M3" in ms: t_call.append( (ms["M3"] - m1).total_seconds() / 3600)
        if "M5" in ms: t_deploy.append((ms["M5"] - m1).total_seconds() / 3600)

    def stats(vals):
        if not vals: return {}
        import statistics
        return {
            "median_hours": round(statistics.median(vals), 1),
            "p75_hours":    round(sorted(vals)[int(len(vals) * 0.75)], 1),
            "p90_hours":    round(sorted(vals)[int(len(vals) * 0.90)], 1),
            "n":            len(vals),
        }

    return {
        "M1_to_M2_provisioning": stats(t_prov),
        "M1_to_M3_first_call":   stats(t_call),
        "M1_to_M5_full_deploy":  stats(t_deploy),
        "teams_reached_M1":      len(team_milestones),
        "teams_reached_M5":      sum(1 for m in team_milestones.values() if "M5" in m),
    }

events  = get_events("2026-04-01", "2026-06-30")
metrics = compute_funnel(events)
for key, val in metrics.items():
    print(f"{key}: {val}")
